---@class StructPetDreamLandPointData
local StructPetDreamLandPointData = LxClass("StructPetDreamLandPointData", nil)
function StructPetDreamLandPointData:StructPetDreamLandPointData()
	---@type string 据点id
	self.id = ""

	---@type string 玩家id
	self.playerId = ""

	---@type number 已占领时间(秒)
	self.time = 0

	---@type number 服务器编码-玩家名称
	self.name = ""

	---@type number 玩家战力
	self.fightPower = 0

	---@type number 保护期结束时间(秒)
	self.endTime = 0

	---@type table<StructRewardItem> 奖励物品列表
	self.itemList = {}

	---@type number 开始占领时间(秒)
	self.starOccupyTime = 0

	---@type number 保护期开始时间(秒)
	self.starProtectTime = 0

	---@type number 被偷袭保护开始时间(秒)
	self.starAttackedTime = 0

	---@type number 被偷袭保护结束时间(秒)
	self.endAttackedTime = 0

	self.playerInfo = nil
end

function StructPetDreamLandPointData:CreateByPb(pb)
	self.id = pb.id

	self.playerId = pb.playerId

	self.time = tonumber(pb.time)

	self.name = pb.name

	self.fightPower = pb.fightPower

	self.endTime = tonumber(pb.endTime)

	self.itemList = {}
	local itemList = pb.itemList or {}
	for i,v in ipairs(itemList) do
		---@type StructRewardItem
		local data = StructRewardItem:New()
		data:CreateByPb(v)
		table.insert(self.itemList,data)
	end

	self.starOccupyTime = tonumber(pb.starOccupyTime)

	self.starProtectTime = tonumber(pb.starProtectTime)

	self.starAttackedTime = tonumber(pb.starAttackedTime)

	self.endAttackedTime = tonumber(pb.endAttackedTime)

	self.playerInfo = nil
	if pb.playerInfo then
		self.playerInfo = pb.playerInfo
	end
end

---@return boolean 是否无初始化保护
function StructPetDreamLandPointData:CheckIsNoInitProtect()
	if self.endTime < 1 then return false end
	local timeLeft = self.endTime - GetTimestamp()
	return timeLeft < 1
end

---@type number 玩家战力
function StructPetDreamLandPointData:GetPlayerPower()
	return self.playerInfo and self.playerInfo.power or 0
end

function StructPetDreamLandPointData:GetMainShowPlayerPower()
	if self:CheckIsMyPoint() then
		-- 如果是玩家自己，显示防守阵型的战力
		local power = gModelFormation:CalcFormationPowerByFormationType(LCombatTypeConst.COMBAT_TYPE_42)
		if power and power > 0 then
			return power
		end
	end
	return self.fightPower
end

---@return boolean 是否无偷袭保护
function StructPetDreamLandPointData:CheckIsNoAttackedProtect()
	if self.endAttackedTime < 1 then return false end
	local timeLeft = self.endAttackedTime - GetTimestamp()
	return timeLeft < 1
end

---@return string 返回名字
function StructPetDreamLandPointData:GetPlayerShowName()
	return self.playerInfo and self.playerInfo.name or ""
end

function StructPetDreamLandPointData:GetServerAndPlayerName()
	return self.name
end

---@return number 返回形象id，role
function StructPetDreamLandPointData:GetShowPlayerInfoFigure()
	if self:CheckIsMyPoint() then
		return gModelPlayer:GetPlayerFigure()
	end
	return self.playerInfo and self.playerInfo.figure or 0
end

---@return string 获取展示spine 名字
function StructPetDreamLandPointData:GetShowPlayerInfoFigureSpine()
	local figure = self:GetShowPlayerInfoFigure()
	if figure < 1 then return end

	---@type V_RoleAdventureImageRef
	local ref = gModelPlayer:GetRoleAdventureImage(figure)
	if ref and not string.isempty(ref.spine) then
		return ref.spine
	end
end

function StructPetDreamLandPointData:GetPlayerId()
	return self.playerInfo and self.playerInfo.playerId
end

function StructPetDreamLandPointData:GetServerId()
	return self.playerInfo and self.playerInfo.serverId
end

function StructPetDreamLandPointData:GetVipLevel()
	return self.playerInfo and self.playerInfo.vipLevel
end

---@return boolean 是否自己的据点
function StructPetDreamLandPointData:CheckIsMyPoint()
	local playerId = gModelPlayer:GetPlayerId()
	local pointPlayerId = self:GetPlayerId()
	return playerId == pointPlayerId
end

---@return boolean 是否有初始化保护
function StructPetDreamLandPointData:CheckHasInitProtect()
	if self.endTime < 1 then return false end
	local timeLeft = self.endTime - GetTimestamp()
	return timeLeft > 0
end

---@return boolean 是否有被偷袭保护
function StructPetDreamLandPointData:CheckHasAttackedProtect()
	if self.endAttackedTime < 1 then return false end
	local timeLeft = self.endAttackedTime - GetTimestamp()
	return timeLeft > 0
end

function StructPetDreamLandPointData:GetProtectEff()
	if self:CheckHasInitProtect() then
		return "fx_ui_mchj_dun_1"
	end
	if self:CheckHasAttackedProtect() then
		return "fx_ui_mchj_dun_2"
	end
end

---@return number 获取开始占领时间
function StructPetDreamLandPointData:GetStarOccupyTime()
	return self.starOccupyTime
end

---@return string 获取已经占领的时间
function StructPetDreamLandPointData:GetHasOccupyTimeStr()
	local timeLeft = GetTimestamp() - self.starOccupyTime
	return LUtil.FormatTimespanNumber(timeLeft)
end

---@return string 获取已经占领的时间 时分秒
function StructPetDreamLandPointData:GetHasOccupyDetailTimeStr()
	local timeLeft = math.floor(GetTimestamp() - self.starOccupyTime)
	return LUtil.FormatTimeStr1(timeLeft)
end

return StructPetDreamLandPointData